import{_ as a,o as i,c as e,ag as t}from"./chunks/framework.DXGyWiRo.js";const k=JSON.parse('{"title":"Energy usage monitoring with TP-Link smart sockets and InfluxDB","description":"Notes on Energy usage monitoring with TP-Link smart sockets and InfluxDB.","frontmatter":{"title":"Energy usage monitoring with TP-Link smart sockets and InfluxDB","description":"Notes on Energy usage monitoring with TP-Link smart sockets and InfluxDB."},"headers":[],"relativePath":"snippets-and-scripts/scripts/influx/bentasker-co-uk-tplink-tapo-kasa-influxdb.md","filePath":"snippets-and-scripts/scripts/influx/bentasker-co-uk-tplink-tapo-kasa-influxdb.md"}'),n={name:"snippets-and-scripts/scripts/influx/bentasker-co-uk-tplink-tapo-kasa-influxdb.md"};function l(o,s,r,p,h,d){return i(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="energy-usage-monitoring-with-tp-link-smart-sockets-and-influxdb" tabindex="-1">Energy usage monitoring with TP-Link smart sockets and InfluxDB <a class="header-anchor" href="#energy-usage-monitoring-with-tp-link-smart-sockets-and-influxdb" aria-label="Permalink to &quot;Energy usage monitoring with TP-Link smart sockets and InfluxDB&quot;">​</a></h1><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li>Type: webpage</li><li>Origin: <a href="https://www.bentasker.co.uk/posts/blog/house-stuff/capturing-energy-usage-info-with-tapo-kasa-and-influxdb.html" target="_blank" rel="noreferrer">https://www.bentasker.co.uk/posts/blog/house-stuff/capturing-energy-usage-info-with-tapo-kasa-and-influxdb.html</a></li><li>Imported: 2026-05-08</li></ul><h2 id="content" tabindex="-1">Content <a class="header-anchor" href="#content" aria-label="Permalink to &quot;Content&quot;">​</a></h2><p>Context: monitoring electricity usage with smart sockets; author previously used TP-Link <strong>Kasa</strong> KP115 plugs. TP-Link moved focus to <strong>Tapo</strong> (separate app). Data collection was done with ad-hoc scripts; this post consolidates polling <strong>Kasa</strong> and <strong>Tapo</strong> devices and writing metrics to <strong>InfluxDB</strong>.</p><h3 id="approach" tabindex="-1">Approach <a class="header-anchor" href="#approach" aria-label="Permalink to &quot;Approach&quot;">​</a></h3><p>Run a small Docker image periodically to poll devices and write stats to InfluxDB:</p><ul><li>Docker Hub: <code>bentasker12/tplink_to_influxdb</code></li><li>Source / non-Docker run: <a href="https://github.com/bentasker/tplink_to_influxdb" target="_blank" rel="noreferrer">https://github.com/bentasker/tplink_to_influxdb</a></li></ul><h3 id="configuration-yaml" tabindex="-1">Configuration (YAML) <a class="header-anchor" href="#configuration-yaml" aria-label="Permalink to &quot;Configuration (YAML)&quot;">​</a></h3><p>Three top-level sections:</p><ol><li><strong><code>kasa</code></strong> — list Kasa devices (IP/hostname + friendly <code>name</code> used in Influx).</li><li><strong><code>tapo</code></strong> — Tapo devices plus <strong>Tapo cloud</strong> credentials (<code>user</code>, <code>passw</code>); auth hits Tapo cloud to obtain a cookie for local access.</li><li><strong><code>influxdb</code></strong> — one or more InfluxDB v2 write API targets (works with InfluxDB Cloud, OSS ≥ 1.8.0 with v2 write API).</li></ol><p><strong>InfluxDB notes:</strong></p><ul><li>Multiple outputs supported (e.g. cloud + local).</li><li>Optional: write via <strong>Telegraf</strong> using the <code>influxdb_v2_listener</code> input.</li><li>OSS ≥ 2.2: can use Edge Data Replication instead of dual-write in the tool.</li></ul><p><strong>Kasa example:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">kasa</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  devices</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;desk-plug&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      ip</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">192.168.3.150</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tumble-dryer&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      ip</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">192.168.3.151</span></span></code></pre></div><p>Note: Kasa “local only” behavior has been broken/removed in the past (TP-Link forum discussions).</p><p><strong>Tapo example:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tapo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  user</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;me@mymail.com&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  passw</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mysecretpass&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  devices</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;washing-machine&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      ip</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">192.168.3.152</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;big-fridge&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      ip</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">192.168.3.153</span></span></code></pre></div><p>Tapo reliance on cloud auth means <strong>less resilient</strong> for purely local monitoring than Kasa.</p><p><strong>Full combined example</strong> (influx + kasa + tapo): see original post; save as e.g. <code>config.yml</code>.</p><h3 id="run-container" tabindex="-1">Run container <a class="header-anchor" href="#run-container" aria-label="Permalink to &quot;Run container&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --name=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tplink_to_influxdb&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --net=host</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -v</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $PWD</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/config.yml:/config.yml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  bentasker12/tplink_to_influxdb:latest</span></span></code></pre></div><ul><li><code>--rm</code> — remove container after exit.</li><li><code>--net=host</code> — optional; allows reaching <code>127.0.0.1</code> on host for local InfluxDB.</li></ul><p>Example stdout:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Plug: desk-plug using 58.992W, today: 0.629 kWh</span></span></code></pre></div><p>On write failure: <code>Failed to send point to &lt;influx name&gt;</code>.</p><h3 id="scheduling-cron" tabindex="-1">Scheduling (cron) <a class="header-anchor" href="#scheduling-cron" aria-label="Permalink to &quot;Scheduling (cron)&quot;">​</a></h3><p>Example (every minute); adjust config path:</p><div class="language-cron vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cron</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>* * * * * docker run --rm --name=&quot;tplink_to_influxdb&quot; -v /home/ben/docker_files/readings_collect/config.yml:/config.yml --net=host bentasker12/tplink_to_influxdb:latest</span></span></code></pre></div><h3 id="influxdb-schema-flux" tabindex="-1">InfluxDB schema / Flux <a class="header-anchor" href="#influxdb-schema-flux" aria-label="Permalink to &quot;InfluxDB schema / Flux&quot;">​</a></h3><ul><li>Measurement: <code>power_watts</code></li><li>Tag: <code>host</code> — set to the configured plug <strong><code>name</code></strong></li><li>Fields: <ul><li><code>consumption</code> — current power (W)</li><li><code>watts_today</code> — reported usage today (Wh)</li></ul></li></ul><p>Example Flux (current consumption for one device; replace <code>\${device}</code>):</p><div class="language-flux vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">flux</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>from(bucket: &quot;Systemstats&quot;)</span></span>
<span class="line"><span>  |&gt; range(start: v.timeRangeStart, stop: v.timeRangeStop)</span></span>
<span class="line"><span>  |&gt; filter(fn: (r) =&gt; r._measurement == &quot;power_watts&quot; and r._field == &quot;consumption&quot;)</span></span>
<span class="line"><span>  |&gt; filter(fn: (r) =&gt; r.host == &quot;\${device}&quot;)</span></span>
<span class="line"><span>  |&gt; group()</span></span>
<span class="line"><span>  |&gt; aggregateWindow(every: v.windowPeriod, fn: last)</span></span>
<span class="line"><span>  |&gt; map(fn: (r) =&gt; ({_value: r._value}))</span></span></code></pre></div><p>Author joins plug usage with <strong>meter</strong> <code>unit_cost</code> from host <code>power-meter</code> to estimate cost (see post for full join example).</p><h3 id="dashboards" tabindex="-1">Dashboards <a class="header-anchor" href="#dashboards" aria-label="Permalink to &quot;Dashboards&quot;">​</a></h3><p>Examples in repo:</p><ul><li>Grafana: <a href="https://github.com/bentasker/tplink_to_influxdb/blob/master/example/grafana_dashboard.json" target="_blank" rel="noreferrer">https://github.com/bentasker/tplink_to_influxdb/blob/master/example/grafana_dashboard.json</a></li><li>Chronograf: <a href="https://github.com/bentasker/tplink_to_influxdb/blob/master/example/chronograf_dashboard.json" target="_blank" rel="noreferrer">https://github.com/bentasker/tplink_to_influxdb/blob/master/example/chronograf_dashboard.json</a></li></ul><h3 id="related-links-from-article" tabindex="-1">Related links (from article) <a class="header-anchor" href="#related-links-from-article" aria-label="Permalink to &quot;Related links (from article)&quot;">​</a></h3><ul><li>Earlier electricity monitoring post: <a href="https://www.bentasker.co.uk/posts/blog/house-stuff/739-monitoring-our-electricity-usage-with-influxdb.html" target="_blank" rel="noreferrer">https://www.bentasker.co.uk/posts/blog/house-stuff/739-monitoring-our-electricity-usage-with-influxdb.html</a></li><li>Kasa discontinued discussion: <a href="https://old.reddit.com/r/TPLinkKasa/comments/scfmy6/what_does_kasa_being_discontinued_mean_going/" target="_blank" rel="noreferrer">https://old.reddit.com/r/TPLinkKasa/comments/scfmy6/what_does_kasa_being_discontinued_mean_going/</a></li><li>Tapo P110 example: <a href="https://www.bentasker.co.uk/posts/blog/house-stuff/how-much-more-energy-efficient-is-eco-mode-on-a-dish-washer.html" target="_blank" rel="noreferrer">https://www.bentasker.co.uk/posts/blog/house-stuff/how-much-more-energy-efficient-is-eco-mode-on-a-dish-washer.html</a></li><li>Improvements milestone: <a href="https://projects.bentasker.co.uk/gils_projects/milestone/utilities/tp-link-to-influxdb/33.html" target="_blank" rel="noreferrer">https://projects.bentasker.co.uk/gils_projects/milestone/utilities/tp-link-to-influxdb/33.html</a></li></ul><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li><strong>Docker-first</strong> workflow: <code>bentasker12/tplink_to_influxdb</code> + YAML for Kasa, Tapo, and Influx outputs.</li><li><strong>Tapo</strong> needs cloud credentials and is weaker for offline/local-only setups than Kasa.</li><li><strong>Influx</strong>: measurement <code>power_watts</code>, tag <code>host</code> = plug name, fields <code>consumption</code> (W) and <code>watts_today</code> (Wh).</li><li><strong>Ops</strong>: use <code>--net=host</code> if Influx listens on localhost; schedule with cron; example Grafana/Chronograf JSON in the GitHub repo.</li></ul>`,41)])])}const u=a(n,[["render",l]]);export{k as __pageData,u as default};
